# cfbfastR::cfbd_team_info(year = 2024) |>
#     dplyr::select(opponent = school, opp_conf = conference) -> opp_confs

# join opponent conferences 
# full_sched <- combined_result |> 
#  dplyr::left_join(opp_confs, by = "opponent")

# write.csv(full_sched, "2024_sched.csv")

sched <- readr::read_csv("2024_sched.csv")

sched |> 
    dplyr::mutate(conf = dplyr::case_match(conf,
                                           "American Athletic" ~ "American",
                                           "Pac-12" ~ "Pac-2",
                                           "Conference USA" ~ "CUSA",
                                           "FBS Independents" ~ "INDIE",
                                           "Mid-American" ~ "MAC",
                                           "Mountain West" ~ "MW",
                                          conf ~ conf  )) |> 
    dplyr::mutate(opp_conf = dplyr::case_match(opp_conf,
                                           "American Athletic" ~ "American",
                                           "Pac-12" ~ "Pac-2",
                                           "Conference USA" ~ "CUSA",
                                           "FBS Independents" ~ "INDIE",
                                           "Mid-American" ~ "MAC",
                                           "Mountain West" ~ "MW",
                                           opp_conf ~ opp_conf  )) |> 
    dplyr::group_by(conf, opp_conf) |> 
    dplyr::summarise(
        opp = dplyr::n(),
        .groups = "drop"  # Explicitly drop the grouping
    ) |> 
    tidyr::pivot_wider(
        names_from = opp_conf,
        values_from = opp,
        values_fill = 0
    ) |> 
    dplyr::mutate(
        dplyr::across(
            -conf,
            ~ifelse(dplyr::cur_column() == conf, "-", as.character(.))
        )
    ) |> 
    dplyr::select(-`NA`)-> conferences
```
