### GT Table for conferences


::: {.cell}

```{.r .cell-code}
conferences |> 
    gt::gt() |> 
    gtExtras::gt_theme_dot_matrix() |> 
    gt::tab_options (
        source_notes.font.size = gt::px(10),
        row.striping.background_color = '#EEEEEE',
        table.font.size = gt::px(12),
        column_labels.text_transform = 'uppercase'
    ) |>
    gt::tab_style(style = list(gt::cell_borders(
        sides = c("left"),
        color = "#eeeeee",
        weight = gt::px(2)
    )),
    locations = list(gt::cells_body(
        columns = gt::everything()
    ))) |> 
  gt::cols_label(
    conf = ""
  ) |> 
  gt::tab_header(title = gt::html("<b>Games Scheduled Between FBS Conferences in 2024</b><hr>")) |> 
  gt::tab_source_note(source_note = gt::html("Data via cfbfastR<br>
  <hr>
                                       <b>Table by Chris (@dadgumboxscores) + Bless your chart | August 28, 2024</b>"))-> conf_tbl 

gtExtras::gtsave_extra(conf_tbl, 
                       filename = "conf_tbl.png",
                       vwidth = 650,
                       expand = 10)

conf_tbl
