clean_sp_table <- function(sp) {
  sp |> 
    dplyr::mutate(team = gsub("[^a-zA-Z]", "", team),
                  sp_rating = `SP+`,
                  sp_off_rating = stringr::str_extract(`Off. SP+`, "\\d+\\.?\\d*"),
                  sp_off_rk = stringr::str_extract(`Off. SP+`,
                                                         pattern = "(?<=\\().*(?=\\))"),
                  sp_def_rk = stringr::str_extract(`Def. SP+`,
                                                         pattern = "(?<=\\().*(?=\\))"),
                  sp_def_rating = stringr::str_extract(`Def. SP+`, "\\d+\\.?\\d*"),
                  sp_st_rk = stringr::str_extract(`ST SP+`,
                                                    pattern = "(?<=\\().*(?=\\))"),
                  sp_st_rating = stringr::str_extract(`ST SP+`, "\\d+\\.?\\d*"),
