  dplyr::mutate(def_pctile = dplyr::percent_rank(sp_def_rating) * 100,
                year = 2023) |> 
  dplyr::filter(team_name == "North Carolina") |> 
  dplyr::select(year, team = team_name, `Def. SP+` = sp_def_rating, def_pctile, def_rk = sp_def_rk)

unc_defense <- total_def |> 
  dplyr::bind_rows(unc_2023) |> 
  dplyr::mutate(
    coach = dplyr::case_when(
      year %in% c(1988:1997) ~ "Mack Brown 1.0",
      year %in% c(1998:2000) ~ "Carl Torbush",
      year %in% c(2001:2006) ~ "John Bunting",
      year %in% c(2007:2010) ~ "Butch Davis",
      year == 2011 ~ "Everett Withers",
      year %in% c(2012:2018) ~ "Larry Fedora",
      year %in% c(2019:2023) ~ "Mack Brown 2.0"
    )
  ) |> 
  dplyr::group_by(coach) |> 
  dplyr::summarise(
    avg_rtg = mean(`Def. SP+`),
    avg_pct = mean(def_pctile),
    sum_data = list(def_pctile),
  ) |> 
  dplyr::mutate(
    record = dplyr::case_when(
      coach == "Mack Brown 1.0" ~ "69-46",
      coach == "Carl Torbush" ~ "17-18",
      coach == "John Bunting" ~ "27-45",
      coach == "Butch Davis" ~ "28-23",
      coach == "Everett Withers" ~ "7-6",
      coach == "Larry Fedora" ~ "45-43",
      coach == "Mack Brown 2.0" ~ "38-27",
  ),
  win_pct =  dplyr::case_when(
      coach == "Mack Brown 1.0" ~ .600,
      coach == "Carl Torbush" ~ .486,
      coach == "John Bunting" ~ .375,
      coach == "Butch Davis" ~ .549,
      coach == "Everett Withers" ~ .539,
      coach == "Larry Fedora" ~ .511,
      coach == "Mack Brown 2.0" ~ .585,
  ),
    rank =  dplyr::case_when(
      coach == "Mack Brown 1.0" ~ 1,
      coach == "Carl Torbush" ~ 2,
      coach == "John Bunting" ~ 3,
      coach == "Butch Davis" ~ 4,
      coach == "Everett Withers" ~ 5,
      coach == "Larry Fedora" ~ 6,
      coach == "Mack Brown 2.0" ~ 8,
  ),
  tenure =  dplyr::case_when(
      coach == "Mack Brown 1.0" ~ "1988-1997",
      coach == "Carl Torbush" ~ "1998-2000",
      coach == "John Bunting" ~ "2001-2006",
      coach == "Butch Davis" ~ "2007-2010",
      coach == "Everett Withers" ~ "2011",
      coach == "Larry Fedora" ~ "2012-2018",
      coach == "Mack Brown 2.0" ~ "2019-Present",
  )
  ) |> 
  dplyr::arrange(-rank) |> 
  dplyr::mutate(win_pct = sprintf("%.3f", win_pct))
